import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"穗石村","description":"穗石村简介","frontmatter":{"lang":"zh-CN","title":"穗石村","description":"穗石村简介"},"headers":[],"relativePath":"infra/hemc/suishi.md","filePath":"infra/hemc/suishi.md","lastUpdated":1784896159000}`),a={name:`infra/hemc/suishi.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /infra/hemc/suishi.md for this page in Markdown format</div><h1 id="穗石村" tabindex="-1">穗石村 <a class="header-anchor" href="#穗石村" aria-label="Permalink to “穗石村”">​</a></h1><p>穗石村紧邻大学城校区，从图书馆与 A1 教学楼之间的道路直行约 3 分钟出校门即达，是日常外食和采购的好去处。</p><h2 id="餐饮" tabindex="-1">餐饮 <a class="header-anchor" href="#餐饮" aria-label="Permalink to “餐饮”">​</a></h2><ul><li><strong>面食/饭类</strong>：震亚牛肉面、隆江猪脚饭</li><li><strong>正餐/聚餐</strong>：北调儿铜炉鸡锅、东北菜、武汉小炒、仙庙烧鸡、鸡公煲</li><li><strong>饮品</strong>：蜜雪冰城、茶百道、幸运咖</li></ul><h2 id="日用采买" tabindex="-1">日用采买 <a class="header-anchor" href="#日用采买" aria-label="Permalink to “日用采买”">​</a></h2><p>穗石村有比校内西亚兴安综合超市规模稍大的私营超市，但没有大润发、沃尔玛之类的大型连锁超市。日常水果、零食和日用品均可在此采购。</p><h2 id="交通接驳" tabindex="-1">交通接驳 <a class="header-anchor" href="#交通接驳" aria-label="Permalink to “交通接驳”">​</a></h2><p>从穗石村返回学校由<strong>东门</strong>进入即可。前往地铁站需穿过整个教学区，相比从生活区西一门前往大学城南站，穗石村到地铁站并不算方便。</p><h2 id="租房" tabindex="-1">租房 <a class="header-anchor" href="#租房" aria-label="Permalink to “租房”">​</a></h2><p>穗石村有可供学生租住的房源，适合考研备考、实习等情况。详细租房经验欢迎有相关经历的同学补充。</p>`,11)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};